import { client, wait } from "@trigger.dev/sdk";

client.defineJob({
  id: "delayed-notify-${trial_id}",
  name: "Delayed Notify",
  version: "1.0.0",
  trigger: client.onTrigger({}),
  run: async (payload, { ctx }) => {
    const { userId, message } = payload;

    // Wait for 10 seconds
    await wait.for({ seconds: 10 });

    // Return result with sent: true and original message
    return {
      sent: true,
      message: message,
    };
  },
});

